const headers = $json.headers || {};
const body = $json.body || {};
const rawBody = typeof $json.rawBody === 'string'
  ? $json.rawBody
  : typeof body === 'string'
    ? body
    : JSON.stringify(body);

const config = {
  discordPublicKey: String($env.DISCORD_PUBLIC_KEY || '').trim(),
  allowedChannelIds: String($env.ALLOWED_CHANNEL_IDS || '')
    .split(',')
    .map((id) => id.trim())
    .filter(Boolean),
  securityReportUrl: String($env.SECURITY_REPORT_URL || 'https://github.com/livepeer/docs/security/advisories/new').trim(),
  rateLimitWindowSec: Number($env.RATE_LIMIT_WINDOW_SEC || 600),
  rateLimitMax: Number($env.RATE_LIMIT_MAX || 3),
  schemaVersion: String($env.DISCORD_ISSUE_SCHEMA_VERSION || '1.0.0').trim(),
};

const toText = (value) => {
  if (value === null || value === undefined) return '';
  if (Array.isArray(value)) return value.join(', ').trim();
  return String(value).trim();
};

const isPlaceholder = (value) => {
  const text = toText(value).toLowerCase().replace(/[`*_]/g, '').trim();
  if (!text || text === '_no response_' || text === 'no response') return true;
  return ['n/a', 'na', 'tbd', 'none', 'unknown', '?'].includes(text);
};

const response = (route, content, extras = {}) => ({
  route,
  response_payload: {
    type: 4,
    data: {
      flags: 64,
      content,
      ...(extras.data || {}),
    },
    ...(extras.topLevel || {}),
  },
  ...extras,
});

const optionMap = (options = []) => {
  const map = {};
  for (const opt of options) {
    map[opt.name] = opt.value;
  }
  return map;
};

const getOption = (map, names, fallback = '') => {
  for (const name of names) {
    if (map[name] !== undefined && map[name] !== null) {
      return map[name];
    }
  }
  return fallback;
};

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  const text = toText(value).toLowerCase();
  return ['true', 'yes', 'y', '1', 'checked', 'confirm'].includes(text);
};

const securityPattern = /\b(vulnerability|exploit|rce|remote code execution|xss|csrf|sql injection|private key|secret leak|credential leak|auth bypass)\b/i;
const subtypeToKind = {
  'factual error': 'kind: factual-error',
  'unclear instructions': 'kind: unclear-instructions',
  'missing prerequisite or context': 'kind: missing-context',
  'broken link or media': 'kind: broken-media-link',
  'ux, readability, or accessibility issue': 'kind: accessibility-ux',
  'structural or navigation issue': 'kind: navigation-structure',
};

const now = Date.now();
const nowIso = new Date(now).toISOString();

let staticData;
try {
  staticData = getWorkflowStaticData('global');
} catch {
  staticData = {};
}

staticData.pending = staticData.pending || {};
staticData.ready = staticData.ready || {};
staticData.rateLimit = staticData.rateLimit || {};

for (const [key, pending] of Object.entries(staticData.pending)) {
  if (!pending?.created_at || now - pending.created_at > 6 * 60 * 60 * 1000) {
    delete staticData.pending[key];
  }
}

for (const [key, ready] of Object.entries(staticData.ready)) {
  if (!ready?.created_at || now - ready.created_at > 6 * 60 * 60 * 1000) {
    delete staticData.ready[key];
  }
}

const verifyDiscordSignature = () => {
  const signature = headers['x-signature-ed25519'] || headers['X-Signature-Ed25519'];
  const timestamp = headers['x-signature-timestamp'] || headers['X-Signature-Timestamp'];

  if (!config.discordPublicKey || !signature || !timestamp || !rawBody) {
    return false;
  }

  try {
    const crypto = require('crypto');
    const message = Buffer.from(`${timestamp}${rawBody}`);
    const signatureBuffer = Buffer.from(signature, 'hex');
    const publicKeyBuffer = Buffer.from(config.discordPublicKey, 'hex');
    const keyPrefix = Buffer.from('302a300506032b6570032100', 'hex');
    const publicKeyDer = Buffer.concat([keyPrefix, publicKeyBuffer]);

    return crypto.verify(
      null,
      message,
      { key: publicKeyDer, format: 'der', type: 'spki' },
      signatureBuffer,
    );
  } catch {
    return false;
  }
};

if (!verifyDiscordSignature()) {
  return [{
    json: {
      route: 'deny',
      response_payload: { error: 'invalid request signature' },
      response_code: 401,
    },
  }];
}

if (body.type === 1) {
  return [{ json: { route: 'ping', response_payload: { type: 1 } } }];
}

const channelId = toText(body.channel_id || body.channel?.id);
const user = body.member?.user || body.user || {};
const userId = toText(user.id);
const username = toText(user.global_name || user.username || 'unknown-user');
const userTag = user.discriminator && user.discriminator !== '0'
  ? `${toText(user.username)}#${toText(user.discriminator)}`
  : username;

if (config.allowedChannelIds.length > 0 && !config.allowedChannelIds.includes(channelId)) {
  return [{
    json: response(
      'deny',
      `This command is only allowed in configured intake channels. Allowed IDs: ${config.allowedChannelIds.join(', ')}`,
    ),
  }];
}

if (body.type === 2) {
  const commandName = toText(body.data?.name).toLowerCase();
  if (commandName !== 'docs-issue') {
    return [{ json: response('deny', 'Unsupported command. Use /docs-issue.') }];
  }

  if (!userId) {
    return [{ json: response('deny', 'Unable to resolve your Discord user ID for intake.') }];
  }

  const userTimestamps = (staticData.rateLimit[userId] || []).filter(
    (ts) => now - ts < config.rateLimitWindowSec * 1000,
  );
  if (userTimestamps.length >= config.rateLimitMax) {
    staticData.rateLimit[userId] = userTimestamps;
    return [{
      json: response(
        'deny',
        `Rate limit reached: max ${config.rateLimitMax} issue intakes per ${config.rateLimitWindowSec} seconds. Please try again later.`,
      ),
    }];
  }
  userTimestamps.push(now);
  staticData.rateLimit[userId] = userTimestamps;

  const options = optionMap(body.data?.options || []);
  const shortFields = {
    title: toText(getOption(options, ['title', 'summary'])),
    area: toText(getOption(options, ['area'])),
    issue_subtype: toText(getOption(options, ['issue_subtype', 'subtype'])),
    page_or_path: toText(getOption(options, ['page_or_path', 'page'])),
    section_anchor: toText(getOption(options, ['section_anchor', 'section'])),
    priority: toText(getOption(options, ['priority'])),
    suggested_improvement: toText(getOption(options, ['suggested_improvement', 'suggestion'])),
    requested_action: toText(getOption(options, ['requested_action', 'action'])),
  };

  const checks = {
    searched_existing: toBool(getOption(options, ['searched_existing', 'searched_issues'], false)),
    enough_detail: toBool(getOption(options, ['enough_detail', 'detail_confirmed'], false)),
  };

  const missingShortFields = Object.entries(shortFields)
    .filter(([, value]) => isPlaceholder(value))
    .map(([key]) => key);

  if (missingShortFields.length > 0) {
    return [{
      json: response(
        'deny',
        `Missing required slash-command options: ${missingShortFields.join(', ')}.`,
      ),
    }];
  }

  if (!checks.searched_existing || !checks.enough_detail) {
    return [{
      json: response(
        'deny',
        'Both confirmation flags must be true: searched_existing and enough_detail.',
      ),
    }];
  }

  const correlationId = `dii-${now.toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

  staticData.pending[correlationId] = {
    created_at: now,
    user_id: userId,
    user_tag: userTag,
    fields: shortFields,
    checks,
    source: {
      guild_id: toText(body.guild_id),
      channel_id: channelId,
      message_id: '',
      user_id: userId,
      user_tag: userTag,
      interaction_timestamp: nowIso,
    },
  };

  const modalPayload = {
    type: 9,
    data: {
      title: 'Docs Issue Details (Phase 1)',
      custom_id: `docs_issue_modal:${correlationId}`,
      components: [
        {
          type: 1,
          components: [
            {
              type: 4,
              custom_id: 'content_problem',
              style: 2,
              label: 'Exact problem statement',
              min_length: 10,
              max_length: 1000,
              required: true,
              placeholder: 'What is wrong, unclear, or incomplete?',
            },
          ],
        },
        {
          type: 1,
          components: [
            {
              type: 4,
              custom_id: 'evidence',
              style: 2,
              label: 'Evidence',
              min_length: 5,
              max_length: 1000,
              required: true,
              placeholder: 'Quote/snippet/log/output supporting the issue.',
            },
          ],
        },
        {
          type: 1,
          components: [
            {
              type: 4,
              custom_id: 'ui_ux_feedback',
              style: 2,
              label: 'UX/readability/accessibility feedback',
              min_length: 3,
              max_length: 1000,
              required: true,
              placeholder: 'Describe readability/navigation/accessibility impact.',
            },
          ],
        },
        {
          type: 1,
          components: [
            {
              type: 4,
              custom_id: 'done_criteria',
              style: 2,
              label: 'Done criteria / acceptance check',
              min_length: 5,
              max_length: 1000,
              required: true,
              placeholder: 'What must be true for this issue to be done?',
            },
          ],
        },
        {
          type: 1,
          components: [
            {
              type: 4,
              custom_id: 'additional_context',
              style: 2,
              label: 'Additional context (optional)',
              max_length: 1000,
              required: false,
              placeholder: 'Links, screenshots, related thread context, etc.',
            },
          ],
        },
      ],
    },
  };

  return [{ json: { route: 'open_modal', response_payload: modalPayload } }];
}

if (body.type === 5) {
  const customId = toText(body.data?.custom_id);
  if (!customId.startsWith('docs_issue_modal:')) {
    return [{ json: response('deny', 'Unsupported modal submission.') }];
  }

  const correlationId = customId.split(':')[1];
  const pending = staticData.pending[correlationId];
  if (!pending) {
    return [{ json: response('deny', 'Intake session expired. Re-run /docs-issue.') }];
  }

  if (pending.user_id !== userId) {
    return [{ json: response('deny', 'Only the original reporter can submit this modal.') }];
  }

  const modalValues = {};
  for (const row of body.data?.components || []) {
    for (const component of row.components || []) {
      modalValues[component.custom_id] = toText(component.value);
    }
  }

  const requiredModalIds = ['content_problem', 'evidence', 'ui_ux_feedback', 'done_criteria'];
  const missingModal = requiredModalIds.filter((id) => isPlaceholder(modalValues[id]));
  if (missingModal.length > 0) {
    return [{
      json: response(
        'deny',
        `Missing required modal fields: ${missingModal.join(', ')}. Re-run /docs-issue and submit complete details.`,
      ),
    }];
  }

  const issueFields = {
    area: pending.fields.area,
    issue_subtype: pending.fields.issue_subtype,
    page_or_path: pending.fields.page_or_path,
    section_anchor: pending.fields.section_anchor,
    content_problem: modalValues.content_problem,
    evidence: modalValues.evidence,
    ui_ux_feedback: modalValues.ui_ux_feedback,
    suggested_improvement: pending.fields.suggested_improvement,
    requested_action: pending.fields.requested_action,
    done_criteria: modalValues.done_criteria,
    priority: pending.fields.priority,
    additional_context: modalValues.additional_context || '',
  };

  const securityText = [
    pending.fields.title,
    ...Object.values(issueFields),
  ].join('\n');

  if (securityPattern.test(securityText)) {
    delete staticData.pending[correlationId];
    delete staticData.ready[correlationId];
    return [{
      json: response(
        'deny',
        `This submission appears security-sensitive. Please use private reporting: ${config.securityReportUrl}`,
      ),
    }];
  }

  const issueBodyPreview = [
    '### Area',
    issueFields.area,
    '',
    '### Issue subtype',
    issueFields.issue_subtype,
    '',
    '### Page URL or file path',
    issueFields.page_or_path,
    '',
    '### Section or anchor',
    issueFields.section_anchor,
    '',
    '### Exact problem statement',
    issueFields.content_problem,
    '',
    '### Evidence',
    issueFields.evidence,
    '',
    '### UX/readability/accessibility feedback',
    issueFields.ui_ux_feedback,
    '',
    '### Suggested improvement',
    issueFields.suggested_improvement,
    '',
    '### Action requested from maintainers',
    issueFields.requested_action,
    '',
    '### Done criteria / acceptance check',
    issueFields.done_criteria,
    '',
    '### Priority',
    issueFields.priority,
    '',
    '### Additional context',
    issueFields.additional_context || 'N/A',
    '',
    '### Submission checks',
    '- [x] I searched existing issues and did not find an equivalent report.',
    '- [x] I provided enough detail for maintainers to reproduce and act.',
  ].join('\n');

  const kindLabel = subtypeToKind[toText(issueFields.issue_subtype).toLowerCase()] || 'kind: (not inferred)';
  const labelsPreview = [
    'docs-v2',
    'help wanted',
    'status: needs-triage',
    'type: documentation',
    'scope: page',
    issueFields.area,
    issueFields.priority,
    kindLabel,
  ].join(', ');

  const truncate = (value, max) => {
    if (value.length <= max) return value;
    return `${value.slice(0, max - 3)}...`;
  };

  const previewMessage = [
    `Preview for [docs-page]: ${pending.fields.title}`,
    '',
    `Inferred labels: ${labelsPreview}`,
    '',
    '```md',
    truncate(issueBodyPreview, 1300),
    '```',
    '',
    'Confirm to create the GitHub issue, or cancel to discard.',
  ].join('\n');

  staticData.ready[correlationId] = {
    created_at: now,
    user_id: userId,
    issue_title: pending.fields.title,
    schema_version: config.schemaVersion,
    template_key: 'docs_page_issue',
    fields: issueFields,
    checks: pending.checks,
    source: pending.source,
  };

  const previewPayload = {
    type: 4,
    data: {
      flags: 64,
      content: previewMessage,
      components: [
        {
          type: 1,
          components: [
            {
              type: 2,
              style: 3,
              label: 'Confirm and create issue',
              custom_id: `docs_issue_confirm:${correlationId}`,
            },
            {
              type: 2,
              style: 4,
              label: 'Cancel',
              custom_id: `docs_issue_cancel:${correlationId}`,
            },
          ],
        },
      ],
    },
  };

  return [{ json: { route: 'modal_preview', response_payload: previewPayload } }];
}

if (body.type === 3) {
  const customId = toText(body.data?.custom_id);

  if (customId.startsWith('docs_issue_cancel:')) {
    const correlationId = customId.split(':')[1];
    const ready = staticData.ready[correlationId];
    if (!ready) {
      return [{ json: response('deny', 'No active preview found. Re-run /docs-issue.') }];
    }
    if (ready.user_id !== userId) {
      return [{ json: response('deny', 'Only the original reporter can cancel this intake.') }];
    }

    delete staticData.ready[correlationId];
    delete staticData.pending[correlationId];

    return [{
      json: {
        route: 'cancel',
        response_payload: {
          type: 7,
          data: {
            content: 'Discord issue intake cancelled. No GitHub issue was created.',
            components: [],
          },
        },
      },
    }];
  }

  if (customId.startsWith('docs_issue_confirm:')) {
    const correlationId = customId.split(':')[1];
    const ready = staticData.ready[correlationId];
    if (!ready) {
      return [{ json: response('deny', 'Intake preview expired. Re-run /docs-issue.') }];
    }
    if (ready.user_id !== userId) {
      return [{ json: response('deny', 'Only the original reporter can confirm this intake.') }];
    }

    const dispatchPayload = {
      schema_version: ready.schema_version,
      template_key: ready.template_key,
      correlation_id: correlationId,
      issue_title: ready.issue_title,
      fields: ready.fields,
      source: {
        ...ready.source,
        guild_id: toText(body.guild_id || ready.source.guild_id),
        channel_id: toText(body.channel_id || ready.source.channel_id),
        message_id: toText(body.message?.id || body.message?.message_reference?.message_id || ''),
        user_id: ready.source.user_id,
        user_tag: ready.source.user_tag,
        interaction_timestamp: nowIso,
      },
      checks: ready.checks,
    };

    delete staticData.ready[correlationId];
    delete staticData.pending[correlationId];

    return [{
      json: {
        route: 'confirm',
        response_payload: {
          type: 7,
          data: {
            content: 'Creating GitHub issue now. I will post the issue link shortly.',
            components: [],
          },
        },
        dispatch_payload: dispatchPayload,
        source: {
          application_id: toText(body.application_id),
          interaction_token: toText(body.token),
        },
      },
    }];
  }

  return [{ json: response('deny', 'Unsupported interaction button.') }];
}

return [{ json: response('deny', 'Unsupported Discord interaction payload.') }];

const payload = $json.dispatch_payload || {};
const source = $json.source || {};

const owner = String($env.GITHUB_OWNER || 'livepeer').trim();
const repo = String($env.GITHUB_REPO || 'docs').trim();
const dispatchToken = String($env.GITHUB_DISPATCH_TOKEN || '').trim();
const eventType = String($env.GITHUB_DISPATCH_EVENT_TYPE || 'discord-issue-intake').trim();
const pollAttempts = Number($env.GITHUB_POLL_ATTEMPTS || 8);
const pollDelayMs = Number($env.GITHUB_POLL_DELAY_MS || 4000);

const correlationId = String(payload.correlation_id || '').trim();
const followupUrl = source.application_id && source.interaction_token
  ? `https://discord.com/api/v10/webhooks/${source.application_id}/${source.interaction_token}`
  : '';

let success = false;
let issueUrl = '';
let issueNumber = null;
let errorMessage = '';

if (!dispatchToken) {
  errorMessage = 'Missing GITHUB_DISPATCH_TOKEN environment variable.';
} else if (!correlationId) {
  errorMessage = 'Missing correlation_id in dispatch payload.';
} else {
  try {
    const dispatchRes = await fetch(`https://api.github.com/repos/${owner}/${repo}/dispatches`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${dispatchToken}`,
        Accept: 'application/vnd.github+json',
        'Content-Type': 'application/json',
        'User-Agent': 'livepeer-discord-issue-intake',
      },
      body: JSON.stringify({
        event_type: eventType,
        client_payload: payload,
      }),
    });

    if (!dispatchRes.ok) {
      throw new Error(`repository_dispatch failed: ${dispatchRes.status} ${await dispatchRes.text()}`);
    }

    const query = `repo:${owner}/${repo} is:issue in:body "discord-intake-id:${correlationId}"`;

    for (let attempt = 1; attempt <= pollAttempts; attempt += 1) {
      const searchRes = await fetch(`https://api.github.com/search/issues?q=${encodeURIComponent(query)}&per_page=1`, {
        headers: {
          Authorization: `Bearer ${dispatchToken}`,
          Accept: 'application/vnd.github+json',
          'User-Agent': 'livepeer-discord-issue-intake',
        },
      });

      if (!searchRes.ok) {
        throw new Error(`issue search failed: ${searchRes.status} ${await searchRes.text()}`);
      }

      const searchData = await searchRes.json();
      if (searchData.total_count > 0 && searchData.items?.[0]) {
        issueUrl = searchData.items[0].html_url;
        issueNumber = searchData.items[0].number;
        success = true;
        break;
      }

      if (attempt < pollAttempts) {
        await new Promise((resolve) => setTimeout(resolve, pollDelayMs));
      }
    }

    if (!success) {
      errorMessage = 'Issue creation was dispatched but not found yet. Check Actions runs for discord-issue-intake.';
    }
  } catch (error) {
    errorMessage = error.message;
  }
}

return [{
  json: {
    success,
    issue_url: issueUrl,
    issue_number: issueNumber,
    correlation_id: correlationId,
    error: errorMessage,
    followup_url: followupUrl,
  },
}];

parameters.value:
={{ $json.success ? `Issue created: ${$json.issue_url}
Issue #${$json.issue_number}
Correlation ID: ${$json.correlation_id}` : `Issue intake submitted, but I could not confirm creation yet. Correlation ID: ${$json.correlation_id}
Error: ${$json.error}` }}
